SELECT * FROM bx_lead
WHERE deleted = 0

    AND (title LIKE CONCAT('%', #{query.keyword}, '%')
    OR customer_name LIKE CONCAT('%', #{query.keyword}, '%')
    OR customer_company LIKE CONCAT('%', #{query.keyword}, '%'))


    AND status IN

        #{status}



    AND level IN

        #{level}



    AND source IN

        #{source}



    AND industry = #{query.industry}


    AND region = #{query.region}


    AND owner_id = #{query.ownerId}


    AND intent_score >= #{query.minIntentScore}


    AND intent_score <= #{query.maxIntentScore}


    AND create_time >= #{query.createTimeStart}


    AND create_time <= #{query.createTimeEnd}


    AND expected_deal_time >= #{query.expectedDealTimeStart}


    AND expected_deal_time <= #{query.expectedDealTimeEnd}


    AND intercept_source_id IS NOT NULL

ORDER BY 


        ${query.sortField}

            ASC
            DESC



        create_time DESC
